import{_ as n,H as e,f as t,i as s}from"./chunks/framework.BHvCMIhP.js";const u=JSON.parse('{"title":"AI Infra 系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"aiInfraLearning/00-写作计划.md","filePath":"aiInfraLearning/00-写作计划.md","lastUpdated":1779559313000}'),l={name:"aiInfraLearning/00-写作计划.md"};function i(r,a,o,p,d,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="ai-infra-系列写作计划" tabindex="-1">AI Infra 系列写作计划 <a class="header-anchor" href="#ai-infra-系列写作计划" aria-label="Permalink to &quot;AI Infra 系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」第 L 项,⭐⭐⭐⭐。 aiLearning 41 篇教了「<strong>模型一侧</strong>」——从感知机到 Transformer 到 RAG / Agent / 微调,把「模型是什么、怎么训、怎么用」讲透了;但都没回答一个核心问题:<strong>一张 H100 单卡 80GB,怎么跑得动 70B 模型?一次训练几千张卡,通信怎么不拖死?推理服务上线后,TTFT 200ms / 输出 50 tok/s 怎么压?</strong><strong>看完这层,你能站在白板前画出一家 AI 公司从 GPU 选型 → 训练集群 → 推理服务 → 成本核算的完整工程链</strong>——vLLM / SGLang / DeepSpeed / Megatron / Ray / FP8 / PagedAttention 不再是「听过的名词」,而是知道每个东西解决什么瓶颈、什么时候上、什么时候是过度工程。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「硬件心智」到「端到端工程化」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>硬件与心智(GPU / HBM / Tensor Core / 浮点格式 / 算力账)</span></span>
<span class="line"><span>   → 推理引擎(vLLM / SGLang / TRT-LLM / KV Cache / PagedAttention / 连续批 / 投机解码)</span></span>
<span class="line"><span>   → 训练框架与并行(DDP / ZeRO / FSDP / TP / PP / 3D 并行 / NCCL / 通信拓扑)</span></span>
<span class="line"><span>   → 量化、压缩与高效微调(PTQ / GPTQ / AWQ / FP8 / KV 量化 / LoRA 服务化)</span></span>
<span class="line"><span>   → 调度与平台(Ray / KubeRay / Slurm / K8s GPU / MIG / 弹性训练)</span></span>
<span class="line"><span>   → 端到端工程化(GPU 选型 / 成本与吞吐 / 可观测性 / Agent 推理 / 未来)</span></span></code></pre></div><p><strong>这个系列不是 PyTorch 教程</strong>——<code>torch.nn</code> 那一层 aiLearning 讲过了,<strong>默认你站在 2026 之后</strong>:大模型推理是 vLLM / SGLang 的天下,训练是 Megatron + DeepSpeed,FP8 在 Hopper 上已经是标配,Ray 是 AI 工程链的事实编排层,KubeRay / SkyPilot 把云上 GPU 弹性变成现实。</p><p>不深入到 CUDA Kernel 内核源码、cuBLAS 汇编、PyTorch C++ 调度器,<strong>而是讲清楚&quot;AI 工程师 / 推理工程师 / Infra 工程师能选型、能调优、能排错、能给 CTO 算账的图景&quot;</strong>——你训一个模型、上一个推理服务、做一次成本估算,这些都站在这套工程链上。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-硬件与心智-01-05" tabindex="-1">第一层:硬件与心智(01-05) <a class="header-anchor" href="#第一层-硬件与心智-01-05" aria-label="Permalink to &quot;第一层:硬件与心智(01-05)&quot;">​</a></h3><ul><li>[x] 01 AI 工程链总览(数据 → 训练 → 推理 → 评测 / 每个工种在做什么 / 这套系列的目标读者)</li><li>[x] 02 GPU 与显存心智(SM / Tensor Core / HBM 带宽 / Roofline / 为什么 LLM 是显存而非算力受限)</li><li>[x] 03 训练 vs 推理的根本不同(前向 vs 反向 / 自回归生成为什么需要 KV Cache / Prefill vs Decode 两阶段)</li><li>[x] 04 浮点格式全景(FP32 / FP16 / BF16 / FP8 / INT8 / INT4 / 精度-性能-显存三角)</li><li>[x] 05 LLM 算力账(一次推理多少 FLOPs / 一次训练多少 GPU 小时 / 一张表把模型/卡数/时长算清楚)</li></ul><h3 id="第二层-推理引擎-06-12" tabindex="-1">第二层:推理引擎(06-12) <a class="header-anchor" href="#第二层-推理引擎-06-12" aria-label="Permalink to &quot;第二层:推理引擎(06-12)&quot;">​</a></h3><ul><li>[x] 06 推理引擎景观(vLLM / SGLang / TensorRT-LLM / TGI / llama.cpp / MLC / 选型矩阵)</li><li>[x] 07 KV Cache 心智(显存占比公式 / 长上下文为什么把卡撑爆 / 为什么所有优化都绕它转)</li><li>[x] 08 PagedAttention(vLLM 核心 / 显存碎片问题 / 块管理 / Copy-on-write 与 Prefix Caching)</li><li>[x] 09 Continuous Batching(静态批 vs 动态批 vs 连续批 / 吞吐-延迟权衡 / In-flight Batching)</li><li>[x] 10 SGLang 与 RadixAttention(多轮共享 KV / 结构化输出 / 与 vLLM 的差异化定位)</li><li>[x] 11 投机解码(Speculative Decoding / 草稿模型 / Medusa / EAGLE / 何时是真加速)</li><li>[x] 12 TensorRT-LLM 心智(Kernel 融合 / Plugin / Quantization Toolkit / 何时它真比 vLLM 快)</li></ul><h3 id="第三层-训练框架与并行-13-19" tabindex="-1">第三层:训练框架与并行(13-19) <a class="header-anchor" href="#第三层-训练框架与并行-13-19" aria-label="Permalink to &quot;第三层:训练框架与并行(13-19)&quot;">​</a></h3><ul><li>[x] 13 数据并行(DP / DDP / 梯度同步 / All-Reduce / Bucket / 同步与异步的代价)</li><li>[x] 14 ZeRO 三阶段(DeepSpeed 核心 / 优化器/梯度/参数分片 / 显存账一图看懂)</li><li>[x] 15 FSDP 心智(PyTorch 原生版 ZeRO / FullyShardedDataParallel / 与 DeepSpeed 的边界)</li><li>[x] 16 张量并行(Megatron-LM / 列切 vs 行切 / All-Reduce 通信成本 / 适用规模)</li><li>[x] 17 流水并行(Pipeline Parallelism / 气泡 / 1F1B / Interleaved Schedule)</li><li>[x] 18 3D 并行与序列并行(TP + PP + DP 怎么组合 / 长上下文的 Sequence / Ring / Ulysses)</li><li>[x] 19 通信库与拓扑(NCCL / RDMA / InfiniBand / NVLink / NVSwitch / 通信才是真正瓶颈)</li></ul><h3 id="第四层-量化、压缩与高效微调-20-24" tabindex="-1">第四层:量化、压缩与高效微调(20-24) <a class="header-anchor" href="#第四层-量化、压缩与高效微调-20-24" aria-label="Permalink to &quot;第四层:量化、压缩与高效微调(20-24)&quot;">​</a></h3><ul><li>[x] 20 量化心智(PTQ vs QAT / 对称非对称 / 校准集 / 精度损失从哪来)</li><li>[x] 21 GPTQ / AWQ / GGUF(权重量化三大主流 / 离群值 / 各自代价与适用场景)</li><li>[x] 22 FP8 训练与推理(Hopper 之后的新标准 / Transformer Engine / E4M3 vs E5M2)</li><li>[x] 23 KV Cache 量化(FP8 KV / INT4 KV / 长上下文真正的杀手锏)</li><li>[x] 24 LoRA / QLoRA 服务化(训练-推理一致性 / Multi-LoRA 路由 / S-LoRA / Punica)</li></ul><h3 id="第五层-调度与平台-25-28" tabindex="-1">第五层:调度与平台(25-28) <a class="header-anchor" href="#第五层-调度与平台-25-28" aria-label="Permalink to &quot;第五层:调度与平台(25-28)&quot;">​</a></h3><ul><li>[x] 25 Ray 心智(Actor / Task / Object Store / 为什么 AI 工程链都在用)</li><li>[x] 26 Ray Serve + vLLM(推理服务化 / 自动扩缩容 / RayLLM)</li><li>[x] 27 K8s 上的 GPU(Device Plugin / MIG / 多租户 / KubeRay / Volcano / 拓扑感知调度)</li><li>[x] 28 Slurm 与 HPC 调度(大模型训练为什么不用 K8s / 多节点 NCCL / 故障恢复)</li></ul><h3 id="第六层-端到端工程化-29-30" tabindex="-1">第六层:端到端工程化(29-30) <a class="header-anchor" href="#第六层-端到端工程化-29-30" aria-label="Permalink to &quot;第六层:端到端工程化(29-30)&quot;">​</a></h3><ul><li>[x] 29 推理服务的成本与吞吐(TTFT / TPOT / Throughput / 一张表算清 GPU 每千 token 成本)</li><li>[x] 30 AI Infra 的未来(Disaggregated Prefill-Decode / 长上下文专用栈 / 多模态推理 / Agent 推理工作负载)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>Transformer / Attention 算子</td><td>aiLearning ✅</td><td>不重复,只在 07-08 讲 KV / PagedAttention 时点名</td></tr><tr><td>预训练 / SFT / RLHF / LoRA 算法</td><td>aiLearning ✅</td><td>不重复,24 只讲 LoRA <strong>服务化</strong>(推理端多路由)</td></tr><tr><td>推理与采样(temperature / top-p)</td><td>aiLearning ✅</td><td>不重复</td></tr><tr><td>RAG / Embedding / 向量库</td><td>aiLearning / dataEngineering ✅</td><td>不重复</td></tr><tr><td>数据预处理 / 特征平台</td><td>dataEngineering ✅</td><td>不重复,29 谈推理时只点数据 SLA</td></tr><tr><td>K8s / Docker 基础</td><td>backendLearning ✅</td><td>不重复,27 只讲 GPU 调度特殊性</td></tr><tr><td>分布式一致性 / 共识</td><td>distributedLearning ✅</td><td>不重复,13-19 只讲 collective 通信语义</td></tr><tr><td>CPU / 缓存 / 进程模型</td><td>osLearning ✅</td><td>不重复,02 GPU 心智用 CPU 做对照</td></tr><tr><td>网络 / TCP / RDMA 协议</td><td>networkLearning ✅</td><td>不重复,19 只讲拓扑对训练吞吐的影响</td></tr><tr><td>监控 / Tracing / SLO</td><td>devopsLearning ✅</td><td>不重复,29 只补 LLM 推理特有指标</td></tr><tr><td>Python / PyTorch 基础</td><td>aiLearning ✅</td><td>不重复,本系列假设你能读懂 <code>model.generate</code></td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么这层是瓶颈 → 心智模型 → 工程落地 → 替代方案与局限&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么这层是瓶颈</span></span>
<span class="line"><span>   - 没它的世界长什么样(上一代是怎么做的,死在哪)</span></span>
<span class="line"><span>   - 它解决的根本问题是什么(显存?吞吐?延迟?精度?成本?)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 心智模型(一张图)</span></span>
<span class="line"><span>   - 显存布局图 / 通信时序图 / 算力账,任选其一</span></span>
<span class="line"><span>   - 关键概念用最少的名词讲清楚</span></span>
<span class="line"><span>   - 公式只写一行,且解释每个变量的工程含义</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程落地</span></span>
<span class="line"><span>   - 最小可跑的一段配置或代码(vLLM 启动参数 / DeepSpeed config / Ray Serve)</span></span>
<span class="line"><span>   - 真实场景:这家公司为什么这么用,踩过什么坑</span></span>
<span class="line"><span>   - 调优 / 监控 / 故障排查的关键指标</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 替代方案与局限</span></span>
<span class="line"><span>   - 同代位竞争者(vLLM vs SGLang vs TRT-LLM / DeepSpeed vs FSDP / Slurm vs K8s)</span></span>
<span class="line"><span>   - 什么场景不该用它</span></span>
<span class="line"><span>   - 现在 2026 之后业界往哪个方向走</span></span></code></pre></div><p>不抄官方文档参数表——<strong>只贴关键的 10-30 行配置或代码</strong>,让读者&quot;看到一次推理 / 一次训练的形状&quot;就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05  心智:看完知道&quot;为什么 LLM 推理是显存受限,FP8 vs BF16 何时该切&quot;</span></span>
<span class="line"><span>06-12  推理:**当下最热**,vLLM / SGLang 是面试与生产的硬通货</span></span>
<span class="line"><span>13-19  训练:**真正的工程难点**,千卡训练 80% 时间在打通信</span></span>
<span class="line"><span>20-24  量化:**降本的关键**,GPTQ / FP8 / KV 量化是上线必备</span></span>
<span class="line"><span>25-28  调度:**平台一侧**,Ray + K8s + Slurm 决定团队上限</span></span>
<span class="line"><span>29-30  端到端:**算账与未来**,看完知道&quot;下一站长什么样&quot;</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 06-12 + 13-19 这 14 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 vLLM 比 HuggingFace <code>generate</code> 吞吐高 10 倍,代价是什么&quot;</li><li>&quot;为什么 70B 模型推理需要 2 张 80GB H100,KV Cache 占了多少&quot;</li><li>&quot;为什么千卡训练 70B 必须 TP + PP + DP 三路并行,只用 DDP 会死在哪&quot;</li><li>&quot;为什么 FSDP 在中等规模够用,百亿以上还得切到 Megatron + DeepSpeed&quot;</li></ul><p>再加上 20-30 这 11 篇,你应该能讲清楚:</p><ul><li>&quot;GPTQ / AWQ / FP8 各降本多少,精度掉多少,什么场景该选哪个&quot;</li><li>&quot;Ray Serve + vLLM 上线一个 LLM 服务,自动扩缩容怎么配,冷启动怎么解&quot;</li><li>&quot;千张 H100 训练一周成本多少,推理服务每千 token 成本多少,瓶颈在哪一步&quot;</li><li>&quot;Disaggregated Inference 为什么是下一站,跟连续批处理是什么关系&quot;</li></ul><p>能讲清楚两题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li><strong>不复述 Transformer 算子细节</strong>——QKV、Softmax、FFN 在 aiLearning 13 讲过了,本系列只关心算子怎么落到显存与通信上</li><li>「先讲个 GPU 编年史 / Volta → Ampere → Hopper → Blackwell」——直接进重点,代次只在性能特性差异时点名</li><li>罗列 vLLM / DeepSpeed 全部 flag——只贴让读者&quot;跑得起来 + 调得动&quot;的最小子集</li><li>「这是面试常考」——读者来这里是为了真懂瓶颈在哪,不是背名词</li><li><strong>不画图就讲 PagedAttention / 3D 并行 / All-Reduce</strong>——这些东西<strong>不画图永远讲不清楚</strong></li><li>抄 NVIDIA / vLLM 官方 Blog——官方文档在那儿,这里只补它没讲透的「为什么」和「什么时候不要用」</li><li>「vLLM vs TRT-LLM 谁更牛」式的口水战——只讲各自擅长的场景,选型留给工程判断</li><li>不区分 Prefill 和 Decode 就讨论延迟——所有推理性能讨论都必须分两阶段,TTFT 和 TPOT 不能混为一谈</li><li>写 CUDA Kernel 编程教程——本系列读者是「调度这些 Kernel 的人」,不是「写这些 Kernel 的人」</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于工程视角</strong>——能选型、能调优、能排错、能给团队和老板算账。</p><p>所有示例配置限制在最小可跑片段,<strong>不教你怎么从零编译一个 vLLM、写一个 PagedAttention CUDA Kernel、或调 NCCL 通信库源码</strong>——那是引擎团队 / Kernel 团队的事,本系列的读者画像是「上面用模型、下面踩 GPU 的应用 / 推理 / Infra 工程师」,你需要懂这些工具是怎么编排起来的,但不需要从 SASS 汇编读起。</p><p><strong>面向 2026:</strong></p><ul><li>默认 NVIDIA H100 / H200 / B200 为主线,A100 作为存量背景,消费级卡(4090 / 5090)只在 11 / 21 单卡量化场景点名</li><li>默认你已经读完 aiLearning,知道 Transformer / KV / Tokenizer / SFT 是什么</li><li>默认你已经会用 Docker / K8s 的基础,本系列只补 GPU 调度的特殊性</li><li>默认主流栈是 PyTorch + vLLM/SGLang + DeepSpeed/Megatron + Ray,JAX / TPU 只在 16 / 25 作为对照出现</li></ul>`,48)])])}const g=n(l,[["render",i]]);export{u as __pageData,g as default};
